#include <stdio.h>
#include <stdlib.h>
#include <limits.h>
#define MAX_N 100005
#define MAX_M 100005
#define INF 1000000000

// Define the structure for a road
typedef struct {
    int from, to;
    int toll;
} Road;

// Define the structure for a priority queue
typedef struct {
    int size;
    Road* roads;
} PriorityQueue;

// Function to create a new priority queue
PriorityQueue* createPriorityQueue(int size) {
    PriorityQueue* queue = (PriorityQueue*) malloc(sizeof(PriorityQueue));
    queue->size = size;
    queue->roads = (Road*) malloc(size * sizeof(Road));
    return queue;
}

// Function to insert a road into the priority queue
void insertRoad(PriorityQueue* queue, Road road) {
    int i;
    for (i = 0; i < queue->size; i++) {
        if (road.toll < queue->roads[i].toll) {
            // Shift the roads to the right to make space for the new road
            int j;
            for (j = queue->size - 1; j > i; j--) {
                queue->roads[j] = queue->roads[j - 1];
            }
            queue->roads[i] = road;
            return;
        }
    }
    // If the road is not inserted, it means the queue is full
    printf("Error: Priority queue is full.\n");
}

// Function to get the road with the minimum toll from the priority queue
Road getMinRoad(PriorityQueue* queue) {
    return queue->roads[0];
}

// Function to update the toll of a road in the priority queue
void updateRoad(PriorityQueue* queue, int from, int to, int newToll) {
    int i;
    for (i = 0; i < queue->size; i++) {
        if (queue->roads[i].from == from && queue->roads[i].to == to) {
            queue->roads[i].toll = newToll;
            // Rebuild the priority queue
            int j;
            for (j = i; j > 0; j--) {
                if (queue->roads[j].toll < queue->roads[j - 1].toll) {
                    // Swap the roads
                    Road temp = queue->roads[j];
                    queue->roads[j] = queue->roads[j - 1];
                    queue->roads[j - 1] = temp;
                } else {
                    break;
                }
            }
            return;
        }
    }
    // If the road is not found, it means the road does not exist in the queue
    printf("Error: Road not found in priority queue.\n");
}

int main() {
    int n, m;
    scanf("%d %d", &n, &m);
    // Create a graph to store the roads
    int** graph = (int**) malloc(n * sizeof(int*));
    for (int i = 0; i < n; i++) {
        graph[i] = (int*) malloc(n * sizeof(int));
        for (int j = 0; j < n; j++) {
            graph[i][j] = INF;
        }
    }
    // Read the roads and store them in the graph
    for (int i = 0; i < m; i++) {
        int from, to, toll;
        scanf("%d %d %d", &from, &to, &toll);
        from--;
        to--;
        graph[from][to] = toll;
    }
    // Create a priority queue to store the roads
    PriorityQueue* queue = createPriorityQueue(n);
    // Insert the roads from the starting city into the priority queue
    for (int i = 0; i < n; i++) {
        if (graph[0][i] != INF) {
            Road road;
            road.from = 0;
            road.to = i;
            road.toll = graph[0][i];
            insertRoad(queue, road);
        }
    }
    // Read the queries and answer them
    int t;
    scanf("%d", &t);
    for (int i = 0; i < t; i++) {
        long long k;
        scanf("%lld", &k);
        // Find the k-th road
        long long count = 0;
        while (count < k) {
            Road road = getMinRoad(queue);
            count++;
            // Update the toll of the road
            int newToll = graph[road.from][road.to] + 1;
            updateRoad(queue, road.from, road.to, newToll);
            // Insert the new road into the priority queue
            for (int j = 0; j < n; j++) {
                if (graph[road.to][j] != INF) {
                    Road newRoad;
                    newRoad.from = road.to;
                    newRoad.to = j;
                    newRoad.toll = graph[road.to][j];
                    insertRoad(queue, newRoad);
                }
            }
        }
        // Print the toll of the k-th road
        printf("%d\n", getMinRoad(queue).toll);
    }
    return 0;
}

