import java.util.PriorityQueue;
import java.util.Scanner;
import java.util.Comparator;

public class Main {
    // Define the structure for a road
    static class Road implements Comparable<Road> {
        int from, to;
        int toll;
        public Road(int from, int to, int toll) {
            this.from = from;
            this.to = to;
            this.toll = toll;
        }
        @Override
        public int compareTo(Road o) {
            return Integer.compare(this.toll, o.toll);
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int n = scanner.nextInt();
        int m = scanner.nextInt();
        // Create a graph to store the roads
        int[][] graph = new int[n][n];
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                graph[i][j] = Integer.MAX_VALUE;
            }
        }
        // Read the roads and store them in the graph
        for (int i = 0; i < m; i++) {
            int from = scanner.nextInt() - 1;
            int to = scanner.nextInt() - 1;
            int toll = scanner.nextInt();
            graph[from][to] = toll;
        }
        // Create a priority queue to store the roads
        PriorityQueue<Road> queue = new PriorityQueue<>();
        // Insert the roads from the starting city into the priority queue
        for (int i = 0; i < n; i++) {
            if (graph[0][i] != Integer.MAX_VALUE) {
                Road road = new Road(0, i, graph[0][i]);
                queue.add(road);
            }
        }
        // Read the queries and answer them
        int t = scanner.nextInt();
        for (int i = 0; i < t; i++) {
            long k = scanner.nextLong();
            // Find the k-th road
            long count = 0;
            while (count < k) {
                Road road = queue.poll();
                count++;
                // Update the toll of the road
                int newToll = graph[road.from][road.to] + 1;
                // Insert the new road into the priority queue
                for (int j = 0; j < n; j++) {
                    if (graph[road.to][j] != Integer.MAX_VALUE) {
                        Road newRoad = new Road(road.to, j, graph[road.to][j]);
                        queue.add(newRoad);
                    }
                }
            }
            // Print the toll of the k-th road
            System.out.println(queue.peek().toll);
        }
    }
}

